  1→//! Revalidation loop: re-execute previously-interesting inputs and classify drift.
  2→//!
  3→//! When a previously-interesting input is re-executed against the current
  4→//! version of a function, these types classify what changed and why.
  5→//! The [`revalidate_behaviors`] function drives the loop: for each behavior
  6→//! in a [`BehaviorMap`], it replays the input via a frontend subprocess,
  7→//! compares observed vs. recorded branch paths (masking nondeterministic
  8→//! fields), and emits a [`RevalidationReport`] with a verdict.
  9→
 10→use serde::{Deserialize, Serialize};
 11→use std::fmt;
 12→use std::time::{SystemTime, UNIX_EPOCH};
 13→
 14→use crate::behavior::BehaviorMap;
 15→use crate::execution_record::BranchDecision;
 16→use crate::frontend::{Frontend, FrontendError};
 17→use crate::interesting_pool::{classify_severity, Severity};
 18→use crate::nondeterminism::NondeterministicField;
 19→use crate::protocol::{Command as ProtoCommand, ResponseResult};
 20→
 21→/// Classification of what happened when replaying a previously-interesting input.
 22→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 23→#[serde(rename_all = "snake_case")]
 24→pub enum RevalidationVerdict {
 25→    /// Behavior unchanged — same branch path and severity.
 26→    Confirmed,
 27→    /// Code fingerprint changed and behavior changed — expected drift.
 28→    ExpectedDrift,
 29→    /// Code unchanged but behavior changed — nondeterminism or environment.
 30→    Flaky,
 31→    /// Code changed and previously-interesting behavior vanished.
 32→    PotentialRegression,
 33→    /// Behavior became less severe (potential silent fix).
 34→    SeverityDowngrade,
 35→    /// Behavior became more severe (potential new bug).
 36→    SeverityUpgrade,
 37→}
 38→
 39→impl fmt::Display for RevalidationVerdict {
 40→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 41→        match self {
 42→            Self::Confirmed => write!(f, "confirmed"),
 43→            Self::ExpectedDrift => write!(f, "expected drift"),
 44→            Self::Flaky => write!(f, "flaky"),
 45→            Self::PotentialRegression => write!(f, "potential regression"),
 46→            Self::SeverityDowngrade => write!(f, "severity downgrade"),
 47→            Self::SeverityUpgrade => write!(f, "severity upgrade"),
 48→        }
 49→    }
 50→}
 51→
 52→/// Result of re-executing a previously-interesting input against the current code.
 53→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 54→pub struct RevalidationReport {
 55→    /// Fully qualified function name.
 56→    pub function_name: String,
 57→    /// The input vector that was replayed.
 58→    pub input_vector: Vec<serde_json::Value>,
 59→    /// Branch path from the original exploration.
 60→    pub expected_branch_path: Vec<BranchDecision>,
 61→    /// Branch path observed during revalidation.
 62→    pub observed_branch_path: Vec<BranchDecision>,
 63→    /// Severity from the original exploration.
 64→    pub expected_severity: Severity,
 65→    /// Severity observed during revalidation, or `None` if the behavior vanished.
 66→    pub observed_severity: Option<Severity>,
 67→    /// Classification of the revalidation outcome.
 68→    pub verdict: RevalidationVerdict,
 69→    /// Milliseconds since Unix epoch when the revalidation was performed.
 70→    pub timestamp_epoch_ms: u64,
 71→}
 72→
 73→/// Returns the current time as milliseconds since Unix epoch.
 74→pub fn now_epoch_ms() -> u64 {
 75→    SystemTime::now()
 76→        .duration_since(UNIX_EPOCH)
 77→        .unwrap_or_default()
 78→        .as_millis() as u64
 79→}
 80→
 81→/// Classify a revalidation outcome into a verdict.
 82→///
 83→/// Priority order: severity changes take precedence over path changes when
 84→/// both the path and severity differ, because severity shifts have more
 85→/// actionable signal. When only the path changed, we distinguish code-change
 86→/// drift from flaky nondeterminism.
 87→pub fn classify_verdict(
 88→    code_changed: bool,
 89→    path_matches: bool,
 90→    expected_severity: Severity,
 91→    observed_severity: Option<Severity>,
 92→) -> RevalidationVerdict {
 93→    match observed_severity {
 94→        // Behavior vanished entirely.
 95→        None => {
 96→            if code_changed {
 97→                RevalidationVerdict::PotentialRegression
 98→            } else {
 99→                RevalidationVerdict::Flaky
100→            }
101→        }
102→        Some(observed) => {
103→            // Check severity shift first — more actionable than path changes.
104→            if observed < expected_severity {
105→                return RevalidationVerdict::SeverityDowngrade;
106→            }
107→            if observed > expected_severity {
108→                return RevalidationVerdict::SeverityUpgrade;
109→            }
110→            // Same severity — classify based on path match.
111→            if path_matches {
112→                RevalidationVerdict::Confirmed
113→            } else if code_changed {
114→                RevalidationVerdict::ExpectedDrift
115→            } else {
116→                RevalidationVerdict::Flaky
117→            }
118→        }
119→    }
120→}
121→
122→/// Derive severity from a recorded behavior's thrown_error field.
123→fn severity_from_behavior(behavior: &crate::behavior::Behavior) -> Severity {
124→    classify_severity(behavior.thrown_error.as_ref(), false)
125→}
126→
127→/// Compare two branch paths, ignoring branches whose divergence is explained
128→/// by nondeterministic fields.
129→///
130→/// Two paths match if they have the same length and each pair shares the same
131→/// `(branch_id, taken)`. Constraint text is ignored — it is symbolic metadata,
132→/// not behavioral output. If any nondeterministic field has path prefix `"branch"`,
133→/// all branch divergences are masked (the whole path is considered nondeterministic).
134→pub fn branch_paths_match(
135→    expected: &[BranchDecision],
136→    observed: &[BranchDecision],
137→    nondeterministic_fields: &[NondeterministicField],
138→) -> bool {
139→    // If any nondeterministic field covers branches wholesale, skip comparison.
140→    if nondeterministic_fields
141→        .iter()
142→        .any(|f| f.field_path == "branch" || f.field_path.starts_with("branch."))
143→    {
144→        return true;
145→    }
146→
147→    if expected.len() != observed.len() {
148→        return false;
149→    }
150→    expected
151→        .iter()
152→        .zip(observed.iter())
153→        .all(|(e, o)| e.branch_id == o.branch_id && e.taken == o.taken)
154→}
155→
156→/// Re-execute each behavior in a [`BehaviorMap`] against the current code
157→/// and classify the result.
158→///
159→/// `current_fingerprint` is the freshly-computed fingerprint of the function's
160→/// source. If it differs from `behavior_map.fingerprint`, the code has changed.
161→/// Nondeterministic fields from the behavior map are used to mask expected
162→/// flakiness in branch path comparisons.
163→///
164→/// Returns one [`RevalidationReport`] per behavior. Frontend errors during
165→/// individual executions produce a `None` observed_severity (behavior vanished).
166→pub async fn revalidate_behaviors(
167→    frontend: &mut Frontend,
168→    behavior_map: &BehaviorMap,
169→    current_fingerprint: Option<&str>,
170→) -> Result<Vec<RevalidationReport>, FrontendError> {
171→    let code_changed = match (&behavior_map.fingerprint, current_fingerprint) {
172→        (Some(old), Some(new)) => old != new,
173→        // Missing fingerprint on either side → conservative: treat as changed.
174→        _ => true,
175→    };
176→
177→    let nondet_fields = &behavior_map.nondeterministic_fields;
178→    let mut reports = Vec::with_capacity(behavior_map.behaviors.len());
179→
180→    for behavior in &behavior_map.behaviors {
181→        let expected_severity = severity_from_behavior(behavior);
182→        let expected_branch_path = &behavior.branch_path;
183→
184→        let exec_result = frontend
185→            .send(ProtoCommand::Execute {
186→                function: behavior_map.function_id.clone(),
187→                inputs: behavior.input_args.clone(),
188→                mocks: vec![],
189→                setup_context: None,
190→            })
191→            .await;
192→
193→        let (observed_branch_path, observed_severity) = match exec_result {
194→            Ok(response) => match response.result {
195→                ResponseResult::Execute(exec) => {
196→                    let sev = classify_severity(exec.thrown_error.as_ref(), false);
197→                    (exec.branch_path.clone(), Some(sev))
198→                }
199→                ResponseResult::Error { .. } => {
200→                    // Frontend returned a protocol-level error — behavior vanished.
201→                    (vec![], None)
202→                }
203→                // Other response types are unexpected for an Execute command.
204→                _ => (vec![], None),
205→            },
206→            Err(_) => {
207→                // Communication failure — treat as behavior vanished.
208→                (vec![], None)
209→            }
210→        };
211→
212→        let path_matches =
213→            branch_paths_match(expected_branch_path, &observed_branch_path, nondet_fields);
214→
215→        let verdict =
216→            classify_verdict(code_changed, path_matches, expected_severity, observed_severity);
217→
218→        reports.push(RevalidationReport {
219→            function_name: behavior_map.function_id.clone(),
220→            input_vector: behavior.input_args.clone(),
221→            expected_branch_path: expected_branch_path.clone(),
222→            observed_branch_path,
223→            expected_severity,
224→            observed_severity,
225→            verdict,
226→            timestamp_epoch_ms: now_epoch_ms(),
227→        });
228→    }
229→
230→    Ok(reports)
231→}
