548→#[cfg(test)]
549→mod proptests {
550→    use super::*;
551→    use crate::test_arbitraries::arb_branch_decision;
552→    use proptest::prelude::*;
553→
554→    fn arb_severity() -> impl Strategy<Value = Severity> {
555→        prop_oneof![
556→            Just(Severity::RarePath),
557→            Just(Severity::HandledError),
558→            Just(Severity::UnhandledError),
559→            Just(Severity::Crash),
560→        ]
561→    }
562→
563→    proptest! {
564→        /// classify_verdict always returns Confirmed when path matches and severity is unchanged.
565→        #[test]
566→        fn confirmed_when_path_and_severity_match(
567→            code_changed in any::<bool>(),
568→            severity in arb_severity(),
569→        ) {
570→            let v = classify_verdict(code_changed, true, severity, Some(severity));
571→            prop_assert_eq!(v, RevalidationVerdict::Confirmed);
572→        }
573→
574→        /// Severity upgrade always wins regardless of path or code_changed.
575→        #[test]
576→        fn severity_upgrade_always_wins(
577→            code_changed in any::<bool>(),
578→            path_matches in any::<bool>(),
579→        ) {
580→            let v = classify_verdict(code_changed, path_matches, Severity::RarePath, Some(Severity::Crash));
581→            prop_assert_eq!(v, RevalidationVerdict::SeverityUpgrade);
582→        }
583→
584→        /// Severity downgrade always wins regardless of path or code_changed.
585→        #[test]
586→        fn severity_downgrade_always_wins(
587→            code_changed in any::<bool>(),
588→            path_matches in any::<bool>(),
589→        ) {
590→            let v = classify_verdict(code_changed, path_matches, Severity::Crash, Some(Severity::RarePath));
591→            prop_assert_eq!(v, RevalidationVerdict::SeverityDowngrade);
592→        }
593→
594→        /// None observed_severity produces PotentialRegression or Flaky (never Confirmed).
595→        #[test]
596→        fn vanished_never_confirmed(
597→            code_changed in any::<bool>(),
598→            severity in arb_severity(),
599→        ) {
600→            let v = classify_verdict(code_changed, false, severity, None);
601→            prop_assert_ne!(v, RevalidationVerdict::Confirmed);
602→        }
603→
604→        /// branch_paths_match is reflexive: any path matches itself.
605→        #[test]
606→        fn branch_paths_match_reflexive(
607→            path in prop::collection::vec(arb_branch_decision(), 0..=5),
608→        ) {
609→            prop_assert!(branch_paths_match(&path, &path, &[]));
610→        }
611→
612→        /// branch_paths_match: different lengths never match (without nondet mask).
613→        #[test]
614→        fn branch_paths_different_length_never_match(
615→            a in prop::collection::vec(arb_branch_decision(), 1..=3),
616→            extra in arb_branch_decision(),
617→        ) {
618→            let mut b = a.clone();
619→            b.push(extra);
620→            prop_assert!(!branch_paths_match(&a, &b, &[]));
621→        }
622→    }
623→}
