2898→/// Run the stale command: check which functions are stale relative to a spec file.
2899→///
2900→/// Returns `Ok(true)` if all functions are fresh, `Ok(false)` if any are stale or removed.
2901→// Each argument corresponds to a CLI flag; this is only called from one callsite.
2902→#[allow(clippy::too_many_arguments)]
2903→async fn run_stale(
2904→    source: &str,
2905→    spec_path: &Path,
2906→    format: &str,
2907→    request_timeout: u64,
2908→    exec_timeout: u64,
2909→    build_timeout: u64,
2910→    memory_limit: Option<u64>,
2911→    log_level: LogLevel,
2912→    project_dir: Option<&Path>,
2913→) -> Result<bool, Box<dyn std::error::Error>> {
2914→    let target = parse_target(source)?;
2915→    let file_str = target.file.to_string_lossy();
2916→    let project_root_str = resolve_project_root(project_dir, &target.file);
2917→
2918→    let req_timeout = Duration::from_secs(request_timeout);
2919→    let config = frontend_config(target.language, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;
2920→    let mut frontend = Frontend::spawn(&config).await.map_err(|e| {
2921→        format!("failed to spawn {} frontend: {e}", target.language.label())
2922→    })?;
2923→
2924→    let analyze_response = frontend
2925→        .send(ProtoCommand::Analyze {
2926→            file: file_str.to_string(),
2927→            function: target.function.clone(),
2928→            project_root: project_root_str,
2929→        })
2930→        .await
2931→        .map_err(|e| format!("analyze failed: {e}"))?;
2932→
2933→    let functions = match &analyze_response.result {
2934→        ResponseResult::Analyze { functions } => functions.clone(),
2935→        ResponseResult::Error { code, message, .. } => {
2936→            shutdown_frontend(frontend).await;
2937→            return Err(format!("analyze error ({code:?}): {message}").into());
2938→        }
