2940→            shutdown_frontend(frontend).await;
2941→            return Err(format!("unexpected analyze response: {other:?}").into());
2942→        }
2943→    };
2944→
2945→    shutdown_frontend(frontend).await;
2946→
2947→    let existing = shatter_core::spec::read_file_spec_bundle(spec_path)
2948→        .map_err(|e| format!("failed to read spec file {}: {e}", spec_path.display()))?;
2949→
2950→    let plan = shatter_core::spec::compute_incremental_plan(&target.file, &functions, &existing)
