  1→//! Disk cache for [`BehaviorMap`]s and [`FunctionSpec`]s, enabling persistence across runs.
  2→//!
  3→//! When shatter explores a function, the resulting behavior map is stored to disk
  4→//! so it can be reloaded in future runs — critical for compositional testing where
  5→//! function B's behavior map is reused when testing function A.
  6→//!
  7→//! Cache entries include the protocol version so that protocol upgrades
  8→//! automatically invalidate stale entries.
  9→
 10→use std::fs;
 11→use std::path::{Path, PathBuf};
 12→
 13→use serde::{Deserialize, Serialize};
 14→
 15→use crate::behavior::BehaviorMap;
 16→use crate::protocol::PROTOCOL_VERSION;
 17→use crate::spec::FunctionSpec;
 18→
 19→/// Errors that can occur during cache operations.
 20→#[derive(Debug, thiserror::Error)]
 21→pub enum CacheError {
 22→    #[error("cache I/O error: {0}")]
 23→    Io(#[from] std::io::Error),
 24→    #[error("cache serialization error: {0}")]
 25→    Serialization(#[from] serde_json::Error),
 26→}
 27→
 28→/// Versioned envelope for cached BehaviorMap entries.
 29→/// Protocol version changes invalidate all cached entries.
 30→#[derive(Debug, Serialize, Deserialize)]
 31→struct BehaviorMapCacheEntry {
 32→    protocol_version: String,
 33→    behavior_map: BehaviorMap,
 34→}
 35→
 36→/// Versioned envelope for cached FunctionSpec entries.
 37→#[derive(Debug, Serialize, Deserialize)]
 38→struct SpecCacheEntry {
 39→    protocol_version: String,
 40→    spec: FunctionSpec,
 41→}
 42→
 43→/// Compute the base path (without extension) for a function ID within a cache directory.
 44→///
 45→/// Mirrors the source tree structure:
 46→/// - `src/auth.ts:validateToken` → `src/auth.ts/validateToken`
 47→/// - `src/auth.ts:TokenValidator.validate` → `src/auth.ts/TokenValidator/validate`
 48→/// - `simpleFunc` → `simpleFunc`
 49→fn cache_base_path(cache_dir: &Path, function_id: &str) -> PathBuf {
 50→    let mut path = cache_dir.to_path_buf();
 51→
 52→    let (file_part, func_part) = match function_id.split_once(':') {
 53→        Some((f, func)) => (Some(f), func),
 54→        None => (None, function_id),
 55→    };
 56→
 57→    if let Some(file) = file_part {
 58→        for component in file.split('/') {
 59→            if !component.is_empty() {
 60→                path.push(sanitize_component(component));
 61→            }
 62→        }
 63→    }
 64→
 65→    match func_part.split_once('.') {
 66→        Some((class_name, method_name)) => {
 67→            path.push(sanitize_component(class_name));
 68→            path.push(sanitize_component(method_name));
 69→        }
 70→        None => {
 71→            path.push(sanitize_component(func_part));
 72→        }
 73→    }
 74→
 75→    path
 76→}
 77→
 78→/// Disk-backed cache for storing and loading [`BehaviorMap`]s.
 79→#[derive(Debug)]
 80→pub struct BehaviorMapCache {
 81→    cache_dir: PathBuf,
 82→}
 83→
 84→impl BehaviorMapCache {
 85→    /// Create a new cache backed by the given directory.
 86→    ///
 87→    /// Creates the directory (and parents) if it doesn't exist.
 88→    pub fn new(cache_dir: PathBuf) -> Result<Self, CacheError> {
 89→        fs::create_dir_all(&cache_dir)?;
 90→        Ok(Self { cache_dir })
 91→    }
 92→
 93→    /// Load a behavior map for the given function ID, if one exists.
 94→    ///
 95→    /// Returns `Ok(None)` on cache miss, protocol version mismatch,
 96→    /// or deserialization failure (gracefully handles old cache format).
 97→    pub fn load(&self, function_id: &str) -> Result<Option<BehaviorMap>, CacheError> {
 98→        let path = self.path_for(function_id);
 99→        match fs::read_to_string(&path) {
100→            Ok(contents) => {
101→                let entry: BehaviorMapCacheEntry = match serde_json::from_str(&contents) {
102→                    Ok(e) => e,
103→                    // Old bare-JSON format or corrupt entry → cache miss
104→                    Err(_) => return Ok(None),
105→                };
106→                if entry.protocol_version != PROTOCOL_VERSION {
107→                    return Ok(None);
108→                }
109→                Ok(Some(entry.behavior_map))
110→            }
111→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
112→            Err(e) => Err(CacheError::Io(e)),
113→        }
114→    }
115→
116→    /// Store a behavior map to disk using atomic write (temp file + rename).
117→    pub fn store(&self, map: &BehaviorMap) -> Result<(), CacheError> {
118→        let path = self.path_for(&map.function_id);
119→        let entry = BehaviorMapCacheEntry {
120→            protocol_version: PROTOCOL_VERSION.to_string(),
121→            behavior_map: map.clone(),
122→        };
123→        let json = serde_json::to_string_pretty(&entry)?;
124→
125→        if let Some(parent) = path.parent() {
126→            fs::create_dir_all(parent)?;
127→        }
128→
129→        let tmp_path = path.with_extension("json.tmp");
130→        fs::write(&tmp_path, json)?;
131→        fs::rename(&tmp_path, &path)?;
132→
133→        Ok(())
134→    }
135→
136→    /// Check whether a cached behavior map exists and its fingerprint matches.
137→    ///
138→    /// Returns `true` if the cache contains a version-compatible map for
139→    /// `function_id` whose fingerprint equals `current_fingerprint`.
140→    pub fn is_fresh(
141→        &self,
142→        function_id: &str,
143→        current_fingerprint: &str,
144→    ) -> Result<bool, CacheError> {
145→        match self.load(function_id)? {
146→            Some(map) => Ok(map
147→                .fingerprint
148→                .as_deref()
149→                .is_some_and(|fp| fp == current_fingerprint)),
150→            None => Ok(false),
151→        }
152→    }
153→
154→    /// Default cache directory relative to a project root: `<project_root>/.shatter/cache/`.
155→    pub fn default_dir(project_root: &Path) -> PathBuf {
156→        project_root.join(".shatter").join("cache")
157→    }
158→
159→    fn path_for(&self, function_id: &str) -> PathBuf {
160→        let mut p = cache_base_path(&self.cache_dir, function_id);
161→        p.set_extension("json");
162→        p
163→    }
164→}
