#[derive(Debug)]
pub struct SpecCache {
    cache_dir: PathBuf,
}

impl SpecCache {
    /// Create a new spec cache backed by the given directory.
    ///
    /// Creates the directory (and parents) if it doesn't exist.
    pub fn new(cache_dir: PathBuf) -> Result<Self, CacheError> {
