 81→/// Classify a revalidation outcome into a verdict.
 82→///
 83→/// Priority order: severity changes take precedence over path changes when
 84→/// both the path and severity differ, because severity shifts have more
 85→/// actionable signal. When only the path changed, we distinguish code-change
 86→/// drift from flaky nondeterminism.
 87→pub fn classify_verdict(
 88→    code_changed: bool,
 89→    path_matches: bool,
 90→    expected_severity: Severity,
 91→    observed_severity: Option<Severity>,
 92→) -> RevalidationVerdict {
 93→    match observed_severity {
 94→        // Behavior vanished entirely.
 95→        None => {
 96→            if code_changed {
 97→                RevalidationVerdict::PotentialRegression
 98→            } else {
 99→                RevalidationVerdict::Flaky
100→            }
101→        }
102→        Some(observed) => {
103→            // Check severity shift first — more actionable than path changes.
104→            if observed < expected_severity {
105→                return RevalidationVerdict::SeverityDowngrade;
106→            }
107→            if observed > expected_severity {
108→                return RevalidationVerdict::SeverityUpgrade;
109→            }
110→            // Same severity — classify based on path match.
111→            if path_matches {
112→                RevalidationVerdict::Confirmed
113→            } else if code_changed {
114→                RevalidationVerdict::ExpectedDrift
115→            } else {
116→                RevalidationVerdict::Flaky
117→            }
118→        }
119→    }
120→}
