127→/// Compare two branch paths, ignoring branches whose divergence is explained
128→/// by nondeterministic fields.
129→///
130→/// Two paths match if they have the same length and each pair shares the same
131→/// `(branch_id, taken)`. Constraint text is ignored — it is symbolic metadata,
132→/// not behavioral output. If any nondeterministic field has path prefix `"branch"`,
133→/// all branch divergences are masked (the whole path is considered nondeterministic).
134→pub fn branch_paths_match(
135→    expected: &[BranchDecision],
136→    observed: &[BranchDecision],
137→    nondeterministic_fields: &[NondeterministicField],
138→) -> bool {
139→    // If any nondeterministic field covers branches wholesale, skip comparison.
140→    if nondeterministic_fields
141→        .iter()
142→        .any(|f| f.field_path == "branch" || f.field_path.starts_with("branch."))
143→    {
144→        return true;
145→    }
146→
147→    if expected.len() != observed.len() {
148→        return false;
149→    }
150→    expected
