                memory_limit,
                cli.project_dir.as_deref(),
                use_color,
                &seeds_dir,
                no_seeds,
            )
            .await
        }
        CliCommand::ExportTests {
            targets,
            framework,
            module_path,
            output,
            max_iterations,
            timeout,
            scope,
            request_timeout,
            exec_timeout,
            build_timeout,
            memory_limit,
