/// A parsed target: `<file>:<function>` for a single function, or `<file>` for all.
#[derive(Debug, Clone, PartialEq)]
struct Target {
    file: PathBuf,
    function: Option<String>,
    language: Language,
}

/// Supported language frontends.
#[derive(Debug, Clone, Copy, PartialEq)]
enum Language {
    TypeScript,
    Go,
    Rust,
}

impl Language {
    fn from_extension(ext: &str) -> Option<Self> {
        match ext {
            "ts" | "tsx" => Some(Language::TypeScript),
            "go" => Some(Language::Go),
            "rs" => Some(Language::Rust),
            _ => None,
        }
    }

    fn label(self) -> &'static str {
        match self {
            Language::TypeScript => "typescript",
            Language::Go => "go",
            Language::Rust => "rust",
        }
    }
}

/// Parse a target string: `<file>:<function>` or just `<file>`.
///
/// If there is no colon, the entire string is treated as a file path (analyze all functions).
fn parse_target(target: &str) -> Result<Target, String> {
    let (file_str, function) = match target.rsplit_once(':') {
        Some((f, func)) if !func.is_empty() => (f, Some(func.to_string())),
        _ => (target, None),
    };

    let file = PathBuf::from(file_str);

    let ext = file
        .extension()
        .and_then(|e| e.to_str())
        .ok_or_else(|| format!("cannot detect language: no file extension in '{file_str}'"))?;

    let language = Language::from_extension(ext)
        .ok_or_else(|| format!("unsupported file extension '.{ext}' in '{file_str}'"))?;

    Ok(Target {
        file,
        function,
        language,
    })
}

/// Validate that all parsed targets refer to existing files.
fn validate_targets(targets: &[Target]) -> Result<(), String> {
    for target in targets {
        if !target.file.exists() {
            return Err(format!("file not found: '{}'", target.file.display()));
        }
    }
    Ok(())
}

/// Build a `FrontendConfig` for the given language, with log level propagation.
/// Check for a custom-built frontend binary at `.shatter/bin/shatter-{lang}-custom`.
fn find_custom_binary(shatter_dir: Option<&Path>, lang: &str) -> Option<PathBuf> {
    let bin = shatter_dir?.join("bin").join(format!("shatter-{lang}-custom"));
    bin.is_file().then_some(bin)
}

/// Search PATH for a binary by name, returning the first match.
fn find_on_path(name: &str) -> Option<PathBuf> {
    let path_var = std::env::var_os("PATH")?;
    std::env::split_paths(&path_var)
        .map(|dir| dir.join(name))
        .find(|p| p.is_file())
}

fn frontend_config(
    language: Language,
    timeout: Duration,
    log_level: LogLevel,
    exec_timeout: u64,
    build_timeout: u64,
    memory_limit: Option<u64>,
    shatter_dir: Option<&Path>,
) -> Result<FrontendConfig, String> {
    let (command, mut args) = match language {
        Language::TypeScript => {
            let bundle_path = embedded_frontend::ensure_extracted()?;
            (
                PathBuf::from("node"),
                vec!["--no-warnings".to_string(), bundle_path.to_string_lossy().into_owned()],
            )
        }
        Language::Go => {
            if let Some(custom) = find_custom_binary(shatter_dir, "go") {
                (custom, vec![])
            } else {
                let binary_path = embedded_go_frontend::ensure_extracted()?;
                (binary_path, vec![])
            }
        }
        Language::Rust => {
            if let Some(custom) = find_custom_binary(shatter_dir, "rust") {
                (custom, vec![])
            } else if let Some(path) = find_on_path("shatter-rust") {
                (path, vec![])
            } else {
                // shatter-rust is outside the workspace, so check both locations
                let candidates = [
                    PathBuf::from("./shatter-rust/target/debug/shatter-rust"),
                    PathBuf::from("./target/debug/shatter-rust"),
                ];
                if let Some(path) = candidates.iter().find(|p| p.is_file()) {
                    (path.clone(), vec![])
                } else {
                    return Err("shatter-rust frontend not found: install it on PATH or build with `cargo build --manifest-path shatter-rust/Cargo.toml`".to_string());
                }
            }
        }
    };

    // Apply memory limit: for TS, --max-old-space-size must come before the script
    if let Some(mb) = memory_limit {
        match language {
            Language::TypeScript => {
                args.insert(0, format!("--max-old-space-size={mb}"));
            }
            Language::Go | Language::Rust => {
                // Go: GOMEMLIMIT is set via env_vars below
                // Rust: no memory limit mechanism yet
            }
        }
    }

    let mut config = FrontendConfig::new(command);
    config.args = args;
    config.request_timeout = timeout;
    apply_frontend_env(&mut config, log_level, exec_timeout, build_timeout);

    if let Some(mb) = memory_limit
        && language == Language::Go
    {
        let bytes = mb * 1024 * 1024;
        config.env_vars.push(("GOMEMLIMIT".to_string(), format!("{bytes}B")));
    }

    Ok(config)
}

/// Apply standard environment variables to a frontend config.
fn apply_frontend_env(
    config: &mut FrontendConfig,
    log_level: LogLevel,
    exec_timeout: u64,
    build_timeout: u64,
) {
    config.env_vars.push((
        LogLevel::ENV_VAR.to_string(),
        log_level.as_str().to_string(),
    ));
    config.env_vars.push((
        "SHATTER_EXEC_TIMEOUT".to_string(),
        exec_timeout.to_string(),
    ));
    config.env_vars.push((
        "SHATTER_BUILD_TIMEOUT".to_string(),
        build_timeout.to_string(),
    ));
}

/// Parse a `--loop-buckets` CLI string into `LoopBuckets`.
/// Accepts "none" (disables bucketing) or comma-separated u32 values like "0,1,2,5".
fn parse_loop_buckets(s: &str) -> Result<explorer::LoopBuckets, Box<dyn std::error::Error>> {
    let trimmed = s.trim();
    if trimmed.eq_ignore_ascii_case("none") {
        return Ok(explorer::LoopBuckets::none());
    }
    let boundaries: Vec<u32> = trimmed
        .split(',')
        .map(|v| v.trim().parse::<u32>())
        .collect::<Result<Vec<_>, _>>()
        .map_err(|e| format!("invalid --loop-buckets value \"{s}\": {e}"))?;
    Ok(explorer::LoopBuckets::from_boundaries(boundaries))
}

/// Run the explore command.
// Each argument corresponds to a CLI flag; grouping into a struct would add indirection
// without improving clarity since this is only called from one callsite.
#[allow(clippy::too_many_arguments)]
async fn run_explore(
    targets: &[String],
    max_iterations: u32,
    timeout: u64,
    timeout_explore: Option<f64>,
    scope_path: Option<&Path>,
    analyze_only: bool,
    _show_clusters: bool,
    cache_dir: Option<&Path>,
    no_cache: bool,
    request_timeout: u64,
    exec_timeout: u64,
    build_timeout: u64,
    inputs_path: Option<&Path>,
    config_path: Option<&Path>,
    output_path: Option<&Path>,
    log_level: LogLevel,
    show_perf: bool,
    colors: &Colors,
    show_spec: bool,
    spec_as_json: bool,
    spec_as_yaml: bool,
    detect_invariants: bool,
    use_concolic: bool,
    solver_timeout: Option<u64>,
    memory_limit: Option<u64>,
    clean: bool,
    dry_run: bool,
    project_dir: Option<&Path>,
    loop_buckets_str: &str,
    use_color: bool,
    seeds_dir: &Path,
    no_seeds: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    let pool_path = if no_seeds { None } else { Some(seeds_dir.join("pool.json")) };
    let loop_buckets = parse_loop_buckets(loop_buckets_str)?;
    let scope_config = match scope_path {
        Some(path) => {
            let config = ScopeConfig::from_file(path)
                .map_err(|e| format!("failed to load scope config: {e}"))?;
            log::info!("Loaded scope config from {}", path.display());
            config
        }
        None => ScopeConfig::default(),
    };

    let _scope_matcher = ScopeMatcher::new(&scope_config)
        .map_err(|e| format!("invalid scope config: {e}"))?;

    let (cache, spec_cache) = if no_cache {
        (None, None)
    } else {
        let dir = match cache_dir {
            Some(p) => p.to_path_buf(),
            None => BehaviorMapCache::default_dir(&std::env::current_dir()?),
        };
        let bm = BehaviorMapCache::new(dir.clone())
            .map_err(|e| format!("failed to initialize cache: {e}"))?;
        let sc = SpecCache::new(dir)
            .map_err(|e| format!("failed to initialize spec cache: {e}"))?;
        (Some(bm), Some(sc))
    };

    let parsed: Vec<Target> = targets
        .iter()
        .map(|t| parse_target(t))
        .collect::<Result<Vec<_>, _>>()?;
    validate_targets(&parsed)?;

    let req_timeout = Duration::from_secs(request_timeout);

    let mut file_spec_bundles: Vec<FileSpecBundle> = Vec::new();

    let report_style = if use_color {
        shatter_core::report_style::ReportStyle::ansi()
    } else {
        shatter_core::report_style::ReportStyle::default()
    };

    // Count total functions across all targets for header/footer.
    let mut total_function_count: usize = 0;
    let mut total_paths: usize = 0;
    let mut total_covered: usize = 0;
    let mut total_lines: u32 = 0;
    let mut header_printed = false;

    for target in &parsed {
        let file_str = target.file.to_string_lossy();
        let func_display = target
            .function
            .as_deref()
            .unwrap_or("(all)");

        let project_root_str = resolve_project_root(project_dir, &target.file);

        if let Some(ref root) = project_root_str {
            log::debug!("Project root: {root}");
        }
        log::debug!(
            "Exploring {file_str}:{func_display} [language={}, max_iterations={max_iterations}]",
            target.language.label()
        );

        let config = frontend_config(target.language, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;
        let mut frontend = Frontend::spawn(&config).await.map_err(|e| {
            format!(
                "failed to spawn {} frontend: {e}",
                target.language.label()
            )
        })?;

        log::debug!(
            "Frontend connected (language={})",
            frontend.language().unwrap_or("unknown")
        );

        // Analyze phase
        let analyze_response = frontend
            .send(ProtoCommand::Analyze {
                file: file_str.to_string(),
                function: target.function.clone(),
                project_root: project_root_str.clone(),
            })
            .await
            .map_err(|e| format!("analyze failed: {e}"))?;

        match &analyze_response.result {
            ResponseResult::Analyze { functions } => {
                log::debug!("Found {} function(s):", functions.len());
                for func in functions {
                    log::debug!("  - {} ({} params, {} branches)",
                        func.name,
                        func.params.len(),
                        func.branches.len(),
                    );
                }
            }
            ResponseResult::Error { code, message, .. } => {
                log::error!("Analyze error ({code:?}): {message}");
                shutdown_frontend(frontend).await;
                continue;
            }
            other => {
                log::error!("Unexpected analyze response: {other:?}");
                shutdown_frontend(frontend).await;
                continue;
            }
        }

        let functions = match &analyze_response.result {
            ResponseResult::Analyze { functions } => functions.clone(),
            _ => unreachable!("already matched above"),
        };

        if analyze_only {
            if log::log_enabled!(log::Level::Info) {
                for func in &functions {
                    eprintln!(
                        "{}{}{}  ({file_str}:{})",
                        colors.bold, func.name, colors.reset, func.start_line
                    );
                    eprintln!(
                        "  {}params: {}, branches: {}{}",
                        colors.dim,
                        func.params.len(),
                        func.branches.len(),
                        colors.reset
                    );
                }
            }
            shutdown_frontend(frontend).await;
            continue;
        }

        // Incremental plan: compare fingerprints against existing spec when --output is set
        use std::collections::HashSet;
        let incremental_plan = if let Some(out) = output_path
            && !clean
            && out.exists()
        {
            match shatter_core::spec::read_file_spec_bundle(out) {
                Ok(existing) => {
                    match shatter_core::spec::compute_incremental_plan(&target.file, &functions, &existing) {
                        Ok(plan) => Some((plan, existing)),
                        Err(e) => {
                            log::debug!("Failed to compute incremental plan: {e}");
                            None
                        }
                    }
                }
                Err(e) => {
                    log::debug!("Failed to read existing spec: {e}");
                    None
                }
            }
        } else {
            None
        };

        let fresh_set: HashSet<String> = incremental_plan
            .as_ref()
            .map(|(plan, _)| plan.fresh.iter().cloned().collect())
            .unwrap_or_default();

        // Dry-run mode: print incremental plan and exit
        if dry_run {
            if let Some((ref plan, _)) = incremental_plan {
                if !plan.stale.is_empty() {
                    eprintln!("Stale ({}):", plan.stale.len());
                    for name in &plan.stale {
                        eprintln!("  {name}");
                    }
                }
                if !plan.fresh.is_empty() {
                    eprintln!("Fresh ({}):", plan.fresh.len());
                    for name in &plan.fresh {
                        eprintln!("  {name}");
                    }
                }
                if !plan.removed.is_empty() {
                    eprintln!("Removed ({}):", plan.removed.len());
                    for name in &plan.removed {
                        eprintln!("  {name}");
                    }
                }
            } else {
                eprintln!("No existing spec to compare against — all {} function(s) are stale.", functions.len());
                for func in &functions {
                    eprintln!("  {}", func.name);
                }
            }
            shutdown_frontend(frontend).await;
            continue;
        }

        if !fresh_set.is_empty() && log::log_enabled!(log::Level::Info) {
            log::info!("Skipping {} fresh function(s):", fresh_set.len());
            for name in &fresh_set {
                log::info!("  {name}");
            }
        }

        // Load .shatter/ config for this target
        let shatter_configs: Vec<ShatterConfig> = if let Some(cp) = config_path {
            // Explicit config bypasses discovery
            let cfg = shatter_config::parse_config(cp)
                .map_err(|e| format!("failed to load config: {e}"))?;
            log::debug!("Loaded config from {}", cp.display());
            vec![cfg]
        } else {
            // Hierarchical discovery from target file's directory
            let target_dir = target.file.parent().unwrap_or(Path::new("."));
            shatter_config::discover_configs(target_dir)
                .map_err(|e| format!("config discovery error: {e}"))?
        };

        // Compute deep fingerprints (call-graph-aware) for spec output.
        let deep_fingerprints: std::collections::HashMap<String, String> =
            shatter_core::fingerprint::compute_deep_fingerprints(&target.file, &functions)
                .unwrap_or_default();

        // Track function count for header/footer.
        total_function_count += functions.len();

        // Print header on first non-analyze-only target.
        if !analyze_only && !header_printed && log::log_enabled!(log::Level::Info) {
            eprint!(
                "\n{bold}\u{2550}\u{2550}\u{2550} Shatter Explore \u{2550}\u{2550}\u{2550}{reset}\n\n",
                bold = report_style.bold,
                reset = report_style.reset,
            );
            header_printed = true;
        }

        // Exploration phase: generate random inputs and execute
        let mut skipped_unexecutable: Vec<(String, Vec<executability::SkipReason>)> = Vec::new();
        let mut file_specs: Vec<shatter_core::spec::FunctionSpec> = Vec::new();
        for func in &functions {
            // Skip fresh functions in incremental mode, but load cached spec if available.
            if fresh_set.contains(&func.name) {
                if show_spec || detect_invariants {
                    let function_id = format!("{}:{}", file_str, func.name);
                    if let Some(ref sc) = spec_cache
                        && let Ok(Some(cached_spec)) = sc.load(&function_id)
                    {
                        file_specs.push(cached_spec);
                    }
                }
                continue;
            }

            let function_id = format!("{}:{}", file_str, func.name);

            // Resolve per-function config
            let resolved = shatter_config::resolve_function_config_with_inputs(
                &function_id,
                target.file.parent().unwrap_or(Path::new(".")),
                inputs_path,
                max_iterations,
                timeout,
            )
            .map_err(|e| format!("config resolution error for {}: {e}", func.name))?;

            if resolved.skip {
                log::debug!("Skipping {} (skip=true in config)", func.name);
                continue;
            }

            // Check for unexecutable parameter types (opaque types like net.Socket).
            let skip_reasons = executability::check_executability(&func.params, &[]);
            if !skip_reasons.is_empty() {
                log::debug!("Skipping {} (unexecutable parameter types)", func.name);
                skipped_unexecutable.push((func.name.clone(), skip_reasons));
                continue;
            }

            // Generate auto-mocks for external dependencies.
            let auto_mocks = shatter_core::auto_mock::generate_auto_mocks(
                &func.dependencies,
                None,
                &resolved.mock_overrides,
                &[],
            );
            let mock_symbols: Vec<String> = auto_mocks.iter().map(|m| m.symbol.clone()).collect();

            let explore_config = ExploreConfig {
                file: file_str.to_string(),
                max_iterations: resolved.max_iterations,
                seed: None,
                mocks: auto_mocks,
                setup_file: resolved.setup.as_ref().map(|p| p.display().to_string()),
                setup_mode: resolved.setup_mode,
                value_sources: shatter_core::input_gen::resolve_value_sources(
                    &func.params,
                    &resolved.param_generators,
                    &resolved.generators,
                ),
                capabilities: shatter_core::orchestrator::FrontendCapabilities::default(),
                user_seeds: vec![],
                candidate_inputs: resolved.candidate_inputs
                    .iter()
                    .map(|input| input.args.clone())
                    .collect(),
                pool_seeds: match &pool_path {
                    Some(pp) => match shatter_core::interesting_pool::load_pool(pp) {
                        Ok(Some(pool)) => shatter_core::input_gen::pool_to_candidate_inputs(&func.params, &pool),
                        _ => vec![],
                    },
                    None => vec![],
                },
                project_root: project_root_str.clone(),
                loop_buckets: loop_buckets.clone(),
                timeout_explore: timeout_explore.map(Duration::from_secs_f64),
            };

            if !resolved.candidate_inputs.is_empty() {
                log::debug!(
                    "Exploring {} ({} candidate input(s) from config)...",
                    func.name,
                    resolved.candidate_inputs.len()
                );
            } else {
                log::debug!("Exploring {}...", func.name);
            }

            let _ = &shatter_configs; // suppress unused warning

            let func_start = Instant::now();

            // Choose exploration strategy: concolic (Z3-backed) or random.
            let explore_result: Result<shatter_core::explorer::ObservationOutput, shatter_core::explorer::ExploreError> = if use_concolic {
                let mut seed_inputs = shatter_core::boundary_dict::generate_boundary_inputs(&func.params);
                let user_inputs: Vec<Vec<serde_json::Value>> = resolved.candidate_inputs
                    .iter()
                    .map(|input| input.args.clone())
                    .collect();

                // Add pool-derived seeds for concolic mode
                if let Some(ref pp) = pool_path
                    && let Ok(Some(pool)) = shatter_core::interesting_pool::load_pool(pp)
                {
                    let pool_candidates = shatter_core::input_gen::pool_to_candidate_inputs(&func.params, &pool);
                    seed_inputs.extend(pool_candidates);
                }

                // Literal-derived seeds: string/number constants from static analysis
                let literal_candidates = shatter_core::input_gen::literals_to_candidate_inputs(&func.params, &func.literals);
                seed_inputs.extend(literal_candidates);

                let concolic_config = shatter_core::orchestrator::ExploreConfig {
                    max_iterations: explore_config.max_iterations as usize,
                    max_executions: (explore_config.max_iterations as usize) * 5,
                    plateau_threshold: 20,
                    mocks: explore_config.mocks.clone(),
                    solver_timeout_ms: solver_timeout.map(|s| s * 1000),
                    timeout_explore: timeout_explore.map(Duration::from_secs_f64),
                };

                match shatter_core::orchestrator::explore(
                    &mut frontend,
                    &func.name,
                    seed_inputs,
                    user_inputs,
                    &func.params,
                    &concolic_config,
                ).await {
                    Ok(mut concolic_result) => {
                        // Fallback: concolic path doesn't call instrument, so no
                        // instrumentable_line_count available. Use raw span for now.
                        concolic_result.total_lines = func.end_line.saturating_sub(func.start_line) + 1;

                        let obs: shatter_core::explorer::ObservationOutput = concolic_result.into();
                        Ok(obs)
                    }
                    Err(shatter_core::orchestrator::ExploreError::Frontend(fe)) => {
                        Err(shatter_core::explorer::ExploreError::Frontend(fe))
                    }
                }
            } else {
                explorer::explore_function(&mut frontend, func, &explore_config).await
            };

            match explore_result {
                Ok(result) => {
                    let wall_time = func_start.elapsed();

                    // Harvest interesting inputs into the cross-function pool.
                    // Applies to both concolic and random explorer paths — provenance doesn't matter.
                    if let Some(ref pp) = pool_path {
                        let mut pool = shatter_core::interesting_pool::load_pool(pp)
                            .unwrap_or_else(|e| {
                                log::warn!("failed to load interesting pool: {e}");
                                None
                            })
                            .unwrap_or_default();
                        let harvested = shatter_core::interesting_pool::harvest_from_exploration(
                            &mut pool,
                            &result.raw_results,
                            &func.params,
                            &func.name,
                        );
                        if harvested > 0
                            && let Err(e) = shatter_core::interesting_pool::save_pool(&pool, pp)
                        {
                            log::warn!("failed to save interesting pool: {e}");
                        }
                    }

                    // Accumulate stats for footer.
                    total_paths += result.unique_paths;
                    total_covered += result.lines_covered;
                    total_lines += result.total_lines;

                    // Run the Analyze stage to get coverage metrics and eq classes.
                    let analyze_output = shatter_core::pipeline::analyze(&result, func);

                    if log::log_enabled!(log::Level::Info) {
                        if log::log_enabled!(log::Level::Trace) {
                            eprint!("{}", explorer::format_exploration_report_verbose(&result));
                        } else {
                            let report_opts = ReportOptions {
                                location: Some(format!("{file_str}:{}-{}", func.start_line, func.end_line)),
                                show_perf,
                                wall_time: Some(wall_time),
                                coverage_metrics: Some(analyze_output.coverage_metrics.clone()),
                                style: report_style.clone(),
                            };
                            eprint!("{}", explorer::format_exploration_report(&result, &report_opts));
                        }
                        if !mock_symbols.is_empty() {
                            eprintln!("  Mocks used: {}", mock_symbols.join(", "));
                        }
                        if use_concolic {
                            eprintln!("  Explorer: concolic (Z3-backed)");
                        }
                        eprintln!();
                    }

                    // Spec output: use eq classes from analyze stage
                    if show_spec || detect_invariants {
                        let eq_classes = &analyze_output.eq_classes;
                        let location = Some(format!("{file_str}:{}-{}", func.start_line, func.end_line));

                        // Use deep fingerprint (call-graph-aware) for spec output.
                        let fingerprint = deep_fingerprints.get(&func.name).cloned();

                        let spec = if detect_invariants {
                            shatter_core::spec::build_spec_with_invariants(
                                &result, eq_classes, location, fingerprint,
                            )
                        } else {
                            shatter_core::spec::build_spec(&result, eq_classes, location, fingerprint)
                        };

                        // Cache the spec for future incremental runs.
                        if let Some(ref sc) = spec_cache
                            && let Err(e) = sc.store(&function_id, &spec)
                        {
                            log::debug!("Failed to cache spec for {function_id}: {e}");
                        }

                        if output_path.is_some() {
                            // Collect for file-level bundle output
                            file_specs.push(spec);
                        } else if spec_as_json {
                            match shatter_core::spec::format_spec_json(&spec) {
                                Ok(json) => println!("{json}"),
                                Err(e) => log::error!("Error serializing spec: {e}"),
                            }
                        } else if spec_as_yaml {
                            match shatter_core::spec::format_spec_yaml(&spec) {
                                Ok(yaml) => print!("{yaml}"),
                                Err(e) => log::error!("Error serializing spec as YAML: {e}"),
                            }
                        } else {
                            print_markdown(&shatter_core::spec::format_spec_markdown(&spec), use_color);
                        }
                    }

                    let behavior_map =
                        BehaviorMap::from_exploration_result(&func.name, &result);
                    if let Some(ref cache) = cache
                        && let Err(e) = cache.store(&behavior_map)
                    {
                        log::warn!("failed to cache behavior map for {}: {e}", func.name);
                    }
                }
                Err(e) => {
                    log::error!("Exploration error for {}: {e}", func.name);
                }
            }
        }

        // Print summary of skipped unexecutable functions.
        if !skipped_unexecutable.is_empty() && log::log_enabled!(log::Level::Info) {
            log::info!(
                "Skipped {} function(s) (unexecutable parameter types):",
                skipped_unexecutable.len()
            );
            for (name, reasons) in &skipped_unexecutable {
                for reason in reasons {
                    log::info!(
                        "  {name}: param {:?} has opaque type {}",
                        reason.param_name, reason.opaque_label
                    );
                }
            }
        }

        // Collect file-level spec bundle when --output is set.
        if output_path.is_some() {
            let current_function_names: HashSet<String> =
                functions.iter().map(|f| f.name.clone()).collect();

            let bundle = if let Some((_, ref existing)) = incremental_plan {
                // Merge newly explored specs with fresh specs carried over from existing
                shatter_core::spec::merge_file_spec_bundles(
                    existing,
                    &file_specs,
                    &current_function_names,
                )
            } else {
                FileSpecBundle {
                    file: file_str.to_string(),
                    functions: file_specs,
                }
            };

            if !bundle.functions.is_empty() {
                file_spec_bundles.push(bundle);
            }
        }

        shutdown_frontend(frontend).await;
    }

    // Print summary footer.
    if header_printed && log::log_enabled!(log::Level::Info) {
        eprint!(
            "{}",
            explorer::format_explore_footer(
                total_paths,
                total_function_count,
                total_covered,
                total_lines,
                &report_style,
            )
        );
    }

    // Write collected file spec bundles to the output path as a single bundle.
    if let Some(out) = output_path
        && !file_spec_bundles.is_empty()
    {
        // Single-target is the primary Make use case; write the first bundle.
        shatter_core::spec::write_file_spec_bundle(&file_spec_bundles[0], out)
            .map_err(|e| format!("failed to write spec bundle to {}: {e}", out.display()))?;
        log::info!(
            "Wrote spec bundle ({} function(s)) to {}",
            file_spec_bundles[0].functions.len(),
            out.display()
        );
    }

    Ok(())
}

/// Run the scan command: explore multiple functions in dependency order.
#[allow(clippy::too_many_arguments)]
async fn run_scan(
    directory: &str,
    language_filter: Option<&str>,
    include_patterns: &[String],
    exclude_patterns: &[String],
    changed: bool,
    since: Option<&str>,
    include_untracked: bool,
    all_functions: bool,
    max_depth: Option<usize>,
    max_iterations: u32,
    timeout_total: u64,
    cache_dir: Option<&Path>,
    no_cache: bool,
    request_timeout: u64,
    exec_timeout: u64,
    build_timeout: u64,
    parallelism: usize,
    timeout_per_fn: u64,
    timeout_explore: Option<f64>,
    output_dir: Option<&Path>,
    report_format_str: &str,
    progress: bool,
    emit_tests: Option<&str>,
    dry_run: bool,
    resume: Option<&Path>,
    mock_config: Option<&Path>,
    core_sample_spec: Option<&str>,
    core_sample_seed: Option<u64>,
    batch_spec: Option<&str>,
    stratum_spec: Option<&str>,
    log_level: LogLevel,
    memory_limit: Option<u64>,
    project_dir: Option<&Path>,
    use_color: bool,
    seeds_dir: &Path,
    no_seeds: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    let scan_pool_path = if no_seeds {
        None
    } else if seeds_dir.is_absolute() {
        Some(seeds_dir.join("pool.json"))
    } else {
        Some(std::path::PathBuf::from(directory).join(seeds_dir).join("pool.json"))
    };
    let report_format: report::ReportFormat = report_format_str
        .parse()
        .map_err(|e: String| -> Box<dyn std::error::Error> { e.into() })?;

    // Validate --emit-tests framework early.
    if let Some(framework) = emit_tests
        && framework != "jest" && framework != "vitest" && framework != "gotest"
    {
        return Err(format!(
            "unsupported framework '{framework}': expected 'jest', 'vitest', or 'gotest'"
        )
        .into());
    }

    // Validate --language if specified.
    if let Some(lang) = language_filter
        && lang != "typescript" && lang != "go" && lang != "rust"
    {
        return Err(format!(
            "unsupported language '{lang}': expected 'typescript', 'go', or 'rust'"
        )
        .into());
    }

    // Resolve directory.
    let root = PathBuf::from(directory);
    if !root.is_dir() {
        return Err(format!("'{}' is not a directory", root.display()).into());
    }
    let root = root
        .canonicalize()
        .map_err(|e| format!("failed to resolve path '{}': {e}", directory))?;

    let project_root_str = resolve_project_root(project_dir, &root);

    if let Some(ref pr) = project_root_str {
        log::debug!("Project root: {pr}");
    }

    // Discover source files.
    let options = DiscoveryOptions {
        include_patterns: include_patterns.to_vec(),
        exclude_patterns: exclude_patterns.to_vec(),
        respect_gitignore: true,
        max_depth,
    };
    let files = if changed || since.is_some() {
        use shatter_core::scm::{ScmProvider, detect_provider};
        let provider = detect_provider(&root)
            .map_err(|e| format!("SCM detection failed: {e}"))?;
        let scm_files = if let Some(base_ref) = since {
            provider.diff_files(&root, base_ref)
        } else {
            provider.changed_files(&root, include_untracked)
        }
        .map_err(|e| format!("SCM file query failed: {e}"))?;

        if scm_files.is_empty() {
            log::info!("No changed files found");
            return Ok(());
        }
        log::info!("SCM reports {} changed file(s)", scm_files.len());

        discovery::filter_file_list(&root, scm_files, &options)
            .map_err(|e| format!("file filtering failed: {e}"))?
    } else {
        discovery::discover_files(&root, &options)
            .map_err(|e| format!("file discovery failed: {e}"))?
    };

    // Filter by language if specified.
    let files: Vec<(PathBuf, DiscoveryLanguage)> = if let Some(lang) = language_filter {
        let target_lang = match lang {
            "typescript" => DiscoveryLanguage::TypeScript,
            "go" => DiscoveryLanguage::Go,
            "rust" => DiscoveryLanguage::Rust,
            _ => unreachable!(),
        };
        files
            .into_iter()
            .filter(|(_, l)| *l == target_lang)
            .collect()
    } else {
        files
    };

    // Filter to languages we can actually analyze (TS, Go).
    let analyzable_files: Vec<(PathBuf, DiscoveryLanguage)> = files
        .into_iter()
        .filter(|(_, lang)| discovery_lang_to_cli_lang(*lang).is_some())
        .collect();

    if analyzable_files.is_empty() {
        log::info!("No supported source files found in {}", root.display());
        return Ok(());
    }

    log::info!(
        "Discovered {} source file(s) in {}",
        analyzable_files.len(),
        root.display(),
    );

    // Spawn frontends for each language.
    let req_timeout = Duration::from_secs(request_timeout);
    let needed_langs: std::collections::HashSet<DiscoveryLanguage> = analyzable_files
        .iter()
        .map(|(_, lang)| *lang)
        .collect();

    let mut frontends: HashMap<DiscoveryLanguage, Frontend> = HashMap::new();
    for lang in &needed_langs {
        let cli_lang = discovery_lang_to_cli_lang(*lang)
            .ok_or_else(|| format!("no frontend for {lang:?}"))?;
        let config = frontend_config(cli_lang, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;
        let frontend = Frontend::spawn(&config).await.map_err(|e| {
            format!("failed to spawn {lang:?} frontend: {e}")
        })?;
        log::debug!(
            "Frontend connected (language={})",
            frontend.language().unwrap_or("unknown")
        );
        frontends.insert(*lang, frontend);
    }

    // Build analysis cache if caching is enabled.
    let analysis_cache = if no_cache {
        None
    } else {
        let dir = match cache_dir {
            Some(p) => p.join("analysis"),
            None => AnalysisCache::default_dir(&std::env::current_dir()?),
        };
        Some(AnalysisCache::new(dir).map_err(|e| format!("failed to initialize analysis cache: {e}"))?)
    };

    // Batch analyze all files.
    let registry = batch_analyze::batch_analyze(
        &mut frontends,
        &analyzable_files,
        analysis_cache.as_ref(),
        project_root_str.as_deref(),
    )
    .await
    .map_err(|e| format!("batch analyze failed: {e}"))?;

    log::debug!(
        "Found {} function(s) across {} file(s)",
        registry.len(),
        analyzable_files.len(),
    );

    // Collect analyses and file map from the registry.
    let mut all_analyses = Vec::new();
    let mut file_map: HashMap<String, String> = HashMap::new();

    for entry in registry.entries() {
        // Skip non-exported functions unless --all is specified.
        if !all_functions && !entry.exported {
            continue;
        }

        file_map.insert(
            entry.name.clone(),
            entry.file_path.to_string_lossy().into_owned(),
        );
        all_analyses.push(shatter_core::protocol::FunctionAnalysis {
            name: entry.name.clone(),
            params: entry.params.clone(),
            return_type: entry.return_type.clone(),
            branches: vec![],
            dependencies: entry.dependencies.clone(),
            exported: entry.exported,
            start_line: entry.start_line,
            end_line: entry.end_line,
            literals: vec![],
            crypto_boundaries: vec![],
        });
    }

    // Filter out functions with unexecutable parameter types.
    let mut skipped_for_executability: Vec<SkippedFunction> = Vec::new();
    all_analyses.retain(|func| {
        let reasons = executability::check_executability(&func.params, &[]);
        if reasons.is_empty() {
            true
        } else {
            let reason = reasons
                .iter()
                .map(|r| format!("param {:?} has opaque type {}", r.param_name, r.opaque_label))
                .collect::<Vec<_>>()
                .join("; ");
            skipped_for_executability.push(SkippedFunction {
                function_name: func.name.clone(),
                reason,
                category: shatter_core::scan_orchestrator::SkipCategory::Expected,
            });
            false
        }
    });

    if !skipped_for_executability.is_empty() {
        log::info!(
            "Skipped {} function(s) (unexecutable parameter types):",
            skipped_for_executability.len()
        );
        for skip in &skipped_for_executability {
            log::info!("  {}: {}", skip.function_name, skip.reason);
        }
    }

    // Parse --stratum spec early so core-sample budget operates on the
    // stratum-filtered set (not the full population).
    let parsed_stratum = if let Some(spec_str) = stratum_spec {
        Some(
            shatter_core::stratum::parse_stratum_spec(spec_str)
                .map_err(|e| e.to_string())?,
        )
    } else {
        None
    };

    // When both --stratum and --core-sample are set, pre-filter analyses by
    // stratum so the core-sample budget is computed against the narrowed set.
    let stratum_pre_applied = if let (Some(spec), Some(_)) = (&parsed_stratum, &core_sample_spec) {
        let cg = CallGraph::from_registry(&registry);
        let layers = cg.topological_layers();
        let max_layer = if layers.is_empty() { 0 } else { layers.len() - 1 };
        let range = shatter_core::stratum::resolve_range(spec, max_layer)?;
        // filter_layers returns qualified names (file::func); extract bare names.
        let selected: std::collections::HashSet<String> =
            shatter_core::stratum::filter_layers(&layers, &range)
                .into_iter()
                .flat_map(|(_, funcs)| funcs.iter().cloned())
                .map(|qn| {
                    // Qualified names are "file_path::name"; extract the bare name.
                    qn.rsplit_once("::").map_or(qn.clone(), |(_, name)| name.to_string())
                })
                .collect();
        let before = all_analyses.len();
        all_analyses.retain(|a| selected.contains(&a.name));
        log::info!(
            "Stratum filter: {} of {} function(s) in selected layers",
            all_analyses.len(),
            before,
        );
        true
    } else {
        false
    };

    // Apply core sample selection if --core-sample is set.
    let mut effective_batch_index: Option<usize> = None;
    let mut total_scope_functions: usize = all_analyses.len();
    let sampling_context = if let Some(spec) = core_sample_spec {
        let budget = shatter_core::core_sample::parse_sample_budget(spec)
            .map_err(|e| -> Box<dyn std::error::Error> { e.into() })?;
        let cg = CallGraph::from_registry(&registry);
        let seed = core_sample_seed
            .unwrap_or_else(|| shatter_core::core_sample::default_seed(directory));
        let cs_config = shatter_core::core_sample::CoreSampleConfig {
            budget,
            seed,
            scan_root: directory.to_string(),
        };
        let entries: Vec<shatter_core::batch_analyze::FunctionEntry> = registry
            .entries()
            .iter()
            .filter(|e| all_analyses.iter().any(|a| a.name == e.name))
            .cloned()
            .collect();
        // Select using batch mode or standard core sample.
        let result = if let Some(batch_str) = batch_spec {
            let parsed_batch = shatter_core::core_sample::parse_batch_spec(batch_str)
                .map_err(|e| -> Box<dyn std::error::Error> { e.into() })?;
            let batch_index = match parsed_batch {
                shatter_core::core_sample::BatchSpec::Single(idx) => idx,
                shatter_core::core_sample::BatchSpec::Next => {
                    let cache_for_detect = if no_cache {
                        None
                    } else {
                        let dir = match cache_dir {
                            Some(d) => d.to_path_buf(),
                            None => shatter_core::cache::BehaviorMapCache::default_dir(
                                &std::env::current_dir()?,
                            ),
                        };
                        shatter_core::cache::BehaviorMapCache::new(dir).ok()
                    };
                    shatter_core::core_sample::detect_next_batch(
                        &entries,
                        &cs_config,
                        cache_for_detect.as_ref(),
                    )
                }
                shatter_core::core_sample::BatchSpec::Range(start, end) => {
                    log::info!(
                        "Batch range {start}-{end}: running batch {start} \
                         (run subsequent batches with --batch {}..{})",
                        start + 1, end,
                    );
                    start
                }
            };
            effective_batch_index = Some(batch_index);
            log::info!("Using batch {batch_index} of core sample");
            shatter_core::core_sample::select_batch(&entries, &cg, &cs_config, batch_index)
        } else {
            shatter_core::core_sample::select_core_sample(&entries, &cg, &cs_config)
        };
        let included = result.all_included();
        let before = all_analyses.len();
        total_scope_functions = before;
        // included contains qualified names (file_path::name); match using file_map.
        all_analyses.retain(|a| {
            if let Some(file) = file_map.get(&a.name) {
                let qn = format!("{}::{}", file, a.name);
                included.contains(&qn)
            } else {
                // No file mapping — fall back to bare name match.
                included.contains(&a.name)
            }
        });
        log::info!(
            "Core sample: selected {} of {} function(s) ({} sampled + {} dependency closure)",
            included.len(),
            before,
            result.selected.len(),
            result.dependency_closure.len(),
        );
        Some(scan_orchestrator::SamplingContext {
            total_functions: before,
            sampled_functions: result.selected.len(),
            closure_functions: result.dependency_closure.len(),
            strata_summary: result.strata_summary,
        })
    } else {
        if batch_spec.is_some() {
            log::warn!("--batch requires --core-sample; ignoring --batch");
        }
        None
    };

    if all_analyses.is_empty() {
        log::info!("No functions found to scan.");
        for frontend in frontends.into_values() {
            shutdown_frontend(frontend).await;
        }
        return Ok(());
    }

    // Shut down analysis frontends before starting parallel exploration.
    for frontend in frontends.into_values() {
        shutdown_frontend(frontend).await;
    }

    // Resolve effective parallelism: 0 means auto-detect (CPU count).
    let effective_parallelism = if parallelism == 0 {
        std::thread::available_parallelism()
            .map(|n| n.get())
            .unwrap_or(1)
    } else {
        parallelism
    };

    // Dry run: show the full exploration plan without executing.
    if dry_run {
        let scan_config = ScanConfig {
            max_iterations_per_function: max_iterations,
            seed: None,
            file_map: file_map.clone(),
            parallelism: effective_parallelism,
            timeout_per_fn: Duration::from_secs(timeout_per_fn),
            cache: None,
            stratum: if stratum_pre_applied { None } else { parsed_stratum.clone() },
            mock_overrides: HashMap::new(),
            resume_path: None,
            timeout_total: None,
            pool_path: scan_pool_path.clone(),
            project_root: project_root_str.clone(),
            config_dir: Some(std::path::PathBuf::from(directory)),
            timeout_explore: timeout_explore.map(Duration::from_secs_f64),
        };
        let plan = scan_orchestrator::format_dry_run_plan(
            &all_analyses,
            &skipped_for_executability,
            &scan_config,
        )
        .map_err(|e| format!("failed to build dry-run plan: {e}"))?;
        eprint!("{plan}");
        return Ok(());
    }

    log::debug!(
        "Scanning {} function(s) in dependency order ({} worker(s), {}s/fn)...",
        all_analyses.len(),
        effective_parallelism,
        timeout_per_fn,
    );

    let cache = if no_cache {
        None
    } else {
        let dir = match cache_dir {
            Some(d) => d.to_path_buf(),
            None => BehaviorMapCache::default_dir(&std::env::current_dir()?),
        };
        Some(std::sync::Arc::new(
            BehaviorMapCache::new(dir).map_err(|e| format!("failed to initialize cache: {e}"))?,
        ))
    };

    // We need a single frontend config for parallel_scan. Pick from the first language.
    let first_lang = needed_langs.iter().next().copied().unwrap();
    let cli_lang = discovery_lang_to_cli_lang(first_lang)
        .ok_or_else(|| format!("no frontend for {first_lang:?}"))?;
    let fe_config = frontend_config(cli_lang, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;

    // Load mock overrides from --mock-config (or .shatter/config.yaml defaults).
    let mock_overrides = if let Some(mc_path) = mock_config {
        let cfg = shatter_config::parse_config(mc_path)
            .map_err(|e| format!("failed to load mock config: {e}"))?;
        cfg.defaults.mocks.unwrap_or_default()
    } else {
        // Try loading from the scanned directory's .shatter/config.yaml
        let config_path = PathBuf::from(directory).join(".shatter").join("config.yaml");
        if config_path.exists() {
            shatter_config::parse_config(&config_path)
                .ok()
                .and_then(|cfg| cfg.defaults.mocks)
                .unwrap_or_default()
        } else {
            HashMap::new()
        }
    };

    let scan_config = ScanConfig {
        max_iterations_per_function: max_iterations,
        seed: None,
        file_map,
        parallelism: effective_parallelism,
        timeout_per_fn: Duration::from_secs(timeout_per_fn),
        cache,
        stratum: if stratum_pre_applied { None } else { parsed_stratum },
        mock_overrides,
        resume_path: resume.map(|p| p.to_path_buf()),
        timeout_total: if timeout_total == 0 { None } else { Some(Duration::from_secs(timeout_total)) },
        pool_path: scan_pool_path,
        project_root: project_root_str.clone(),
        config_dir: Some(std::path::PathBuf::from(directory)),
        timeout_explore: timeout_explore.map(Duration::from_secs_f64),
    };

    let scan_start = Instant::now();
    let total_functions = all_analyses.len();

    log::info!(
        "Scanning {} function(s) in dependency order...",
        total_functions,
    );

    match scan_orchestrator::parallel_scan(&fe_config, &all_analyses, &scan_config).await {
        Ok(mut result) => {
            result.sampling = sampling_context;
            let elapsed = scan_start.elapsed();

            for (i, fr) in result.function_results.iter().enumerate() {
                if progress {
                    let elapsed_ms = elapsed.as_millis() as u64;
                    let event = report::ProgressEvent::new(
                        &fr.function_name,
                        i + 1,
                        total_functions,
                        elapsed_ms,
                    );
                    if let Some(json) = event.to_json() {
                        eprintln!("{json}");
                    }
                } else {
                    log::info!(
                        "[{}/{}] {} ({:.1}s elapsed)",
                        i + 1,
                        total_functions,
                        fr.function_name,
                        elapsed.as_secs_f64(),
                    );
                }
            }

            print_markdown(&scan_orchestrator::format_parallel_scan_report(&result), use_color);

            // Record batch state and print cumulative progress.
            let batch_state = if let Some(batch_idx) = effective_batch_index {
                let batch_state_path = PathBuf::from(directory)
                    .join(".shatter")
                    .join("batch-state.json");

                let file_paths: Vec<&str> = scan_config
                    .file_map
                    .values()
                    .map(|s| s.as_str())
                    .collect();
                let scan_id =
                    shatter_core::checkpoint::ScanCheckpoint::compute_scan_id(&file_paths);

                let mut state = match shatter_core::batch_state::BatchState::load(&batch_state_path) {
                    Ok(Some(s)) if s.scan_id == scan_id => s,
                    Ok(Some(_)) => {
                        log::info!("batch state scan_id mismatch, starting fresh");
                        shatter_core::batch_state::BatchState::new(
                            scan_id,
                            total_scope_functions,
                        )
                    }
                    Ok(None) => shatter_core::batch_state::BatchState::new(
                        scan_id,
                        total_scope_functions,
                    ),
                    Err(e) => {
                        log::warn!("failed to load batch state: {e}, starting fresh");
                        shatter_core::batch_state::BatchState::new(
                            "unknown".to_string(),
                            total_scope_functions,
                        )
                    }
                };

                let summary =
                    shatter_core::batch_state::BatchSummary::from_scan_result(batch_idx, &result);
                state.record_batch(summary);

                if let Err(e) = state.save(&batch_state_path) {
                    log::warn!("failed to save batch state: {e}");
                }

                print_markdown(
                    &shatter_core::batch_state::format_cumulative_batch_section(&state, batch_idx),
                    use_color,
                );

                Some(state)
            } else {
                None
            };

            let report_dir = output_dir
                .map(PathBuf::from)
                .unwrap_or_else(|| PathBuf::from("./shatter-report/"));
            let scan_report = report::generate_report(
                &result,
                &scan_config.file_map,
                batch_state.as_ref(),
            );

            match report_format {
                report::ReportFormat::Json => {
                    match report::write_report(&scan_report, &report_dir) {
                        Ok(path) => log::info!("Wrote JSON report to {}", path.display()),
                        Err(e) => log::error!("Failed to write JSON report: {e}"),
                    }
                }
                report::ReportFormat::Markdown => {
                    match report::write_markdown_report(&scan_report, &report_dir) {
                        Ok(path) => log::info!("Wrote markdown report to {}", path.display()),
                        Err(e) => log::error!("Failed to write markdown report: {e}"),
                    }
                }
                report::ReportFormat::Both => {
                    match report::write_report(&scan_report, &report_dir) {
                        Ok(path) => log::info!("Wrote JSON report to {}", path.display()),
                        Err(e) => log::error!("Failed to write JSON report: {e}"),
                    }
                    match report::write_markdown_report(&scan_report, &report_dir) {
                        Ok(path) => log::info!("Wrote markdown report to {}", path.display()),
                        Err(e) => log::error!("Failed to write markdown report: {e}"),
                    }
                }
            }

            // Emit test files if --emit-tests was specified.
            if let Some(framework) = emit_tests {
                let tests_dir = output_dir
                    .map(PathBuf::from)
                    .unwrap_or_else(|| report_dir.clone());

                if let Err(e) = emit_test_files(&result, &scan_config.file_map, framework, &tests_dir) {
                    log::error!("Failed to emit test files: {e}");
                }
            }
        }
        Err(e) => {
            log::error!("Scan error: {e}");
        }
    }

    Ok(())
}

/// Run the diff command: compare two snapshots and report regressions.
///
/// Returns `Ok(true)` if there are regressions (nonzero exit), `Ok(false)` if clean.
fn run_diff(
    snapshot_path: &Path,
    current_path: &Path,
    output_json: bool,
    use_color: bool,
) -> Result<bool, Box<dyn std::error::Error>> {
    let previous = snapshot::Snapshot::read_from_file(snapshot_path)
        .map_err(|e| format!("failed to read previous snapshot '{}': {e}", snapshot_path.display()))?;
    let current = snapshot::Snapshot::read_from_file(current_path)
        .map_err(|e| format!("failed to read current snapshot '{}': {e}", current_path.display()))?;

    let result = snapshot::diff(&previous, &current);

    if output_json {
        let json = serde_json::to_string_pretty(&result)
            .map_err(|e| format!("failed to serialize diff result: {e}"))?;
        println!("{json}");
    } else {
        print_markdown(&result.format_report(), use_color);
    }

    Ok(result.has_regressions())
}

/// Run the spec-diff command: compare two function specifications.
///
/// Returns `Ok(true)` if there are regressions (nonzero exit), `Ok(false)` if clean.
fn run_spec_diff(
    old_path: &Path,
    new_path: &Path,
    output_json: bool,
    use_color: bool,
) -> Result<bool, Box<dyn std::error::Error>> {
    let old_contents = std::fs::read_to_string(old_path)
        .map_err(|e| format!("failed to read old spec '{}': {e}", old_path.display()))?;
    let new_contents = std::fs::read_to_string(new_path)
        .map_err(|e| format!("failed to read new spec '{}': {e}", new_path.display()))?;

    let old_spec: shatter_core::spec::FunctionSpec = serde_json::from_str(&old_contents)
        .map_err(|e| format!("failed to parse old spec '{}': {e}", old_path.display()))?;
    let new_spec: shatter_core::spec::FunctionSpec = serde_json::from_str(&new_contents)
        .map_err(|e| format!("failed to parse new spec '{}': {e}", new_path.display()))?;

    let result = shatter_core::spec_diff::diff_specs(&old_spec, &new_spec);

    if output_json {
        let json = shatter_core::spec_diff::format_spec_diff_json(&result)
            .map_err(|e| format!("failed to serialize spec diff: {e}"))?;
        println!("{json}");
    } else {
        print_markdown(&shatter_core::spec_diff::format_spec_diff_text(&result), use_color);
    }

    Ok(result.has_regressions())
}

/// Run the export-tests command: explore targets and generate test code.
#[allow(clippy::too_many_arguments)]
async fn run_export_tests(
    targets: &[String],
    framework: &str,
    module_path: &str,
    output_path: Option<&Path>,
    max_iterations: u32,
    _timeout: u64,
    scope_path: Option<&Path>,
    request_timeout: u64,
    exec_timeout: u64,
    build_timeout: u64,
    _log_level: LogLevel,
    memory_limit: Option<u64>,
    project_dir: Option<&Path>,
) -> Result<(), Box<dyn std::error::Error>> {
    // Validate framework
    if framework != "jest" && framework != "vitest" && framework != "gotest" {
        return Err(format!("unsupported framework '{framework}': expected 'jest', 'vitest', or 'gotest'").into());
    }

    let _scope_config = match scope_path {
        Some(path) => {
            let config = ScopeConfig::from_file(path)
                .map_err(|e| format!("failed to load scope config: {e}"))?;
            log::info!("Loaded scope config from {}", path.display());
            config
        }
        None => ScopeConfig::default(),
    };

    let parsed: Vec<Target> = targets
        .iter()
        .map(|t| parse_target(t))
        .collect::<Result<Vec<_>, _>>()?;
    validate_targets(&parsed)?;

    let req_timeout = Duration::from_secs(request_timeout);
    let mut all_output = String::new();

    for target in &parsed {
        let file_str = target.file.to_string_lossy();
        let func_display = target.function.as_deref().unwrap_or("(all)");
        let project_root_str = resolve_project_root(project_dir, &target.file);

        log::info!("Exploring {file_str}:{func_display} for test export...");

        let config = frontend_config(target.language, req_timeout, LogLevel::Warn, exec_timeout, build_timeout, memory_limit, None)?;
        let mut frontend = Frontend::spawn(&config).await.map_err(|e| {
            format!("failed to spawn {} frontend: {e}", target.language.label())
        })?;

        // Analyze
        let analyze_response = frontend
            .send(ProtoCommand::Analyze {
                file: file_str.to_string(),
                function: target.function.clone(),
                project_root: project_root_str.clone(),
            })
            .await
            .map_err(|e| format!("analyze failed: {e}"))?;

        let functions = match &analyze_response.result {
            ResponseResult::Analyze { functions } => functions.clone(),
            ResponseResult::Error { code, message, .. } => {
                log::error!("Analyze error ({code:?}): {message}");
                shutdown_frontend(frontend).await;
                continue;
            }
            other => {
                log::error!("Unexpected analyze response: {other:?}");
                shutdown_frontend(frontend).await;
                continue;
            }
        };

        // Explore each function and generate tests
        let explore_config = ExploreConfig {
            file: file_str.to_string(),
            max_iterations,
            seed: None,
            mocks: vec![],
            setup_file: None,
            setup_mode: shatter_core::config::SetupMode::PerFunction,
            value_sources: vec![],
            capabilities: shatter_core::orchestrator::FrontendCapabilities::default(),
            user_seeds: vec![],
            candidate_inputs: vec![],
            pool_seeds: vec![],
            project_root: project_root_str.clone(),
            loop_buckets: explorer::LoopBuckets::default(),
            timeout_explore: None,
        };

        for func in &functions {
            log::info!("Exploring {}...", func.name);

            match explorer::explore_function(&mut frontend, func, &explore_config).await {
                Ok(result) => {
                    let behavior_map = BehaviorMap::from_exploration_result(&func.name, &result);

                    let test_code = match framework {
                        "jest" => export::generate_jest_tests(&behavior_map, &func.name, module_path),
                        "vitest" => export::generate_vitest_tests(&behavior_map, &func.name, module_path),
                        "gotest" => export::generate_go_tests(&behavior_map, &func.name, module_path),
                        _ => unreachable!("validated above"),
                    };

                    all_output.push_str(&test_code);
                    all_output.push('\n');
                }
                Err(e) => {
                    log::error!("Exploration error for {}: {e}", func.name);
                }
            }
        }

        shutdown_frontend(frontend).await;
    }

    match output_path {
        Some(path) => {
            std::fs::write(path, &all_output)
                .map_err(|e| format!("failed to write to '{}': {e}", path.display()))?;
            log::info!("Wrote tests to {}", path.display());
        }
        None => {
            print!("{all_output}");
        }
    }

    Ok(())
}

/// Generate test files from scan results and write them to a directory.
///
/// Each function's behavior map produces a separate test file named after
/// the function. The framework determines the format (jest, vitest, gotest).
fn emit_test_files(
    result: &scan_orchestrator::ParallelScanResult,
    file_map: &HashMap<String, String>,
    framework: &str,
    output_dir: &Path,
) -> Result<(), Box<dyn std::error::Error>> {
    std::fs::create_dir_all(output_dir)
        .map_err(|e| format!("failed to create test output directory '{}': {e}", output_dir.display()))?;

    let mut files_written = 0u32;

    for func_result in &result.function_results {
        if func_result.behavior_map.behaviors.is_empty() {
            continue;
        }

        let func_name = &func_result.function_name;
        let module_path = file_map
            .get(func_name)
            .map(|p| {
                let p = Path::new(p);
                let stem = p.with_extension("");
                format!("./{}", stem.display())
            })
            .unwrap_or_else(|| ".".to_string());

        let (test_code, file_ext) = match framework {
            "jest" => (
                export::generate_jest_tests(&func_result.behavior_map, func_name, &module_path),
                "test.ts",
            ),
            "vitest" => (
                export::generate_vitest_tests(&func_result.behavior_map, func_name, &module_path),
                "test.ts",
            ),
            "gotest" => {
                let package = file_map
                    .get(func_name)
                    .and_then(|p| Path::new(p).parent())
                    .and_then(|d| d.file_name())
                    .and_then(|n| n.to_str())
                    .unwrap_or("main");
                (
                    export::generate_go_tests(&func_result.behavior_map, func_name, package),
                    "test.go",
                )
            }
            _ => return Err(format!("unsupported framework '{framework}'").into()),
        };

        let file_name = format!("{func_name}.{file_ext}");
        let file_path = output_dir.join(&file_name);
        std::fs::write(&file_path, &test_code)
            .map_err(|e| format!("failed to write test file '{}': {e}", file_path.display()))?;
        files_written += 1;
    }

    println!("Emitted {files_written} test file(s) to {}", output_dir.display());
    Ok(())
}

/// Map discovery Language to CLI Language for frontend_config.
fn discovery_lang_to_cli_lang(lang: DiscoveryLanguage) -> Option<Language> {
    match lang {
        DiscoveryLanguage::TypeScript => Some(Language::TypeScript),
        DiscoveryLanguage::Go => Some(Language::Go),
        DiscoveryLanguage::Rust => Some(Language::Rust),
    }
}

/// Run the run command: discover, analyze, build call graph, explore, and report.
#[allow(clippy::too_many_arguments)]
async fn run_run(
    path: &str,
    output_dir: Option<&Path>,
    max_iterations: u32,
    timeout: u64,
    analyze_only: bool,
    request_timeout: u64,
    exec_timeout: u64,
    build_timeout: u64,
    log_level: LogLevel,
    memory_limit: Option<u64>,
    project_dir: Option<&Path>,
    use_color: bool,
) -> Result<(), Box<dyn std::error::Error>> {
    let start = Instant::now();

    // Check for URL input (not yet supported)
    if path.starts_with("http://") || path.starts_with("https://") || path.starts_with("git@") {
        return Err("URL/git clone input is not yet supported. Please provide a local directory path.".into());
    }

    let root = PathBuf::from(path);
    if !root.is_dir() {
        return Err(format!("'{}' is not a directory", root.display()).into());
    }

    let root = root.canonicalize()
        .map_err(|e| format!("failed to resolve path '{}': {e}", path))?;

    let project_root_str = resolve_project_root(project_dir, &root);

    if let Some(ref pr) = project_root_str {
        log::debug!("Project root: {pr}");
    }
    log::debug!("Shatter run: {}", root.display());

    // Step 1: Discover files
    log::debug!("Discovering source files...");
    let options = DiscoveryOptions::default();
    let files = discovery::discover_files(&root, &options)
        .map_err(|e| format!("file discovery failed: {e}"))?;

    if files.is_empty() {
        log::info!("No supported source files found in {}", root.display());
        return Ok(());
    }

    // Group by language for reporting
    let mut ts_files = Vec::new();
    let mut go_files = Vec::new();
    let mut rs_files = Vec::new();
    for (p, lang) in &files {
        match lang {
            DiscoveryLanguage::TypeScript => ts_files.push(p.clone()),
            DiscoveryLanguage::Go => go_files.push(p.clone()),
            DiscoveryLanguage::Rust => rs_files.push(p.clone()),
        }
    }

    log::debug!("Found {} file(s):", files.len());
    if !ts_files.is_empty() {
        log::debug!("  TypeScript: {}", ts_files.len());
    }
    if !go_files.is_empty() {
        log::debug!("  Go: {}", go_files.len());
    }
    if !rs_files.is_empty() {
        log::debug!("  Rust: {}", rs_files.len());
    }

    // Filter to languages we can actually analyze (TS, Go)
    let analyzable_files: Vec<(PathBuf, DiscoveryLanguage)> = files
        .into_iter()
        .filter(|(_, lang)| discovery_lang_to_cli_lang(*lang).is_some())
        .collect();

    if analyzable_files.is_empty() {
        log::info!("No analyzable source files found (supported: TypeScript, Go, Rust).");
        return Ok(());
    }

    // Step 2: Spawn frontends for each language
    let req_timeout = Duration::from_secs(request_timeout);
    let mut frontends: HashMap<DiscoveryLanguage, Frontend> = HashMap::new();

    let needed_langs: std::collections::HashSet<DiscoveryLanguage> = analyzable_files
        .iter()
        .map(|(_, lang)| *lang)
        .collect();

    for lang in &needed_langs {
        let cli_lang = discovery_lang_to_cli_lang(*lang)
            .ok_or_else(|| format!("no frontend for {lang:?}"))?;
        let config = frontend_config(cli_lang, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;
        let frontend = Frontend::spawn(&config).await.map_err(|e| {
            format!("failed to spawn {lang:?} frontend: {e}")
        })?;
        log::debug!(
            "Frontend connected (language={})",
            frontend.language().unwrap_or("unknown")
        );
        frontends.insert(*lang, frontend);
    }

    // Step 3: Batch analyze
    log::debug!("Analyzing {} file(s)...", analyzable_files.len());
    let registry = batch_analyze::batch_analyze(
        &mut frontends,
        &analyzable_files,
        None,
        project_root_str.as_deref(),
    )
    .await
    .map_err(|e| format!("batch analyze failed: {e}"))?;

    let total_functions = registry.len();
    let total_branches: usize = registry.entries().iter().map(|e| e.branch_count).sum();

    log::debug!("Found {} function(s) with {} total branch(es)", total_functions, total_branches);

    if total_functions == 0 {
        log::info!("No functions found to explore.");
        shutdown_all_frontends(frontends).await;
        return Ok(());
    }

    // Step 4: Build call graph
    log::debug!("Building call graph...");
    let call_graph = CallGraph::from_registry(&registry);
    let layers = call_graph.topological_layers();
    let cycles = call_graph.cycle_groups();

    log::debug!(
        "{} node(s), {} edge(s), {} layer(s), {} cycle(s)",
        call_graph.node_count(),
        call_graph.edge_count(),
        layers.len(),
        cycles.len(),
    );

    if analyze_only {
        print_summary_report(
            &root,
            &ts_files,
            &go_files,
            &rs_files,
            &registry,
            &call_graph,
            &layers,
            &cycles,
            &[],
            start.elapsed(),
            use_color,
        );

        if let Some(dir) = output_dir {
            write_analysis_report(dir, &registry, &call_graph, &root)?;
        }

        shutdown_all_frontends(frontends).await;
        return Ok(());
    }

    // Step 5: Explore in dependency order (layer by layer)
    log::debug!("Exploring functions in dependency order...");

    let mut exploration_results: Vec<(String, explorer::ObservationOutput)> = Vec::new();

    for (layer_idx, layer) in layers.iter().enumerate() {
        log::debug!("Layer {} ({} function(s)):", layer_idx, layer.len());

        for qualified_name in layer {
            let entry = match registry.get(qualified_name) {
                Some(e) => e,
                None => continue,
            };

            // Determine the language of this file
            let ext = entry.file_path.extension().and_then(|e| e.to_str()).unwrap_or("");
            let disc_lang = match DiscoveryLanguage::from_extension(ext) {
                Some(l) => l,
                None => continue,
            };

            let frontend = match frontends.get_mut(&disc_lang) {
                Some(f) => f,
                None => continue,
            };

            // Analyze to get FunctionAnalysis (needed for explore_function)
            let analyze_response = frontend
                .send(ProtoCommand::Analyze {
                    file: entry.file_path.to_string_lossy().into_owned(),
                    function: Some(entry.name.clone()),
                    project_root: project_root_str.clone(),
                })
                .await
                .map_err(|e| format!("analyze failed for {qualified_name}: {e}"))?;

            let func_analysis = match &analyze_response.result {
                ResponseResult::Analyze { functions } => {
                    functions.iter().find(|f| f.name == entry.name).cloned()
                }
                _ => None,
            };

            let Some(func_analysis) = func_analysis else {
                log::warn!("Skipping {}: could not get analysis", entry.name);
                continue;
            };

            log::debug!("Exploring {}...", entry.name);

            let explore_config = ExploreConfig {
                file: entry.file_path.to_string_lossy().into_owned(),
                max_iterations,
                seed: None,
                mocks: vec![],
                setup_file: None,
                setup_mode: shatter_core::config::SetupMode::PerFunction,
                value_sources: vec![],
                capabilities: shatter_core::orchestrator::FrontendCapabilities::default(),
                user_seeds: vec![],
                candidate_inputs: vec![],
                pool_seeds: vec![],
                project_root: project_root_str.clone(),
                loop_buckets: explorer::LoopBuckets::default(),
                timeout_explore: None,
                };

            match explorer::explore_function(frontend, &func_analysis, &explore_config).await {
                Ok(result) => {
                    log::debug!(
                        "{}: {} path(s), {}/{} lines",
                        entry.name, result.unique_paths, result.lines_covered, result.total_lines
                    );
                    exploration_results.push((qualified_name.clone(), result));
                }
                Err(e) => {
                    log::debug!("{}: error: {e}", entry.name);
                }
            }

            // Check overall timeout
            if start.elapsed() > Duration::from_secs(timeout) {
                log::warn!("Timeout reached ({timeout}s), stopping exploration.");
                break;
            }
        }

        if start.elapsed() > Duration::from_secs(timeout) {
            break;
        }
    }

    eprintln!();

    // Step 6: Print summary report
    print_summary_report(
        &root,
        &ts_files,
        &go_files,
        &rs_files,
        &registry,
        &call_graph,
        &layers,
        &cycles,
        &exploration_results,
        start.elapsed(),
        use_color,
    );

    // Step 7: Write output files if requested
    if let Some(dir) = output_dir {
        write_run_report(dir, &call_graph, &exploration_results)?;
    }

    shutdown_all_frontends(frontends).await;
    Ok(())
}

/// Print a markdown-style summary report to stdout, rendered with termimad when `use_color` is true.
#[allow(clippy::too_many_arguments)]
fn print_summary_report(
    root: &Path,
    ts_files: &[PathBuf],
    go_files: &[PathBuf],
    rs_files: &[PathBuf],
    registry: &FunctionRegistry,
    call_graph: &CallGraph,
    layers: &[Vec<String>],
    cycles: &[Vec<String>],
    exploration_results: &[(String, explorer::ObservationOutput)],
    elapsed: Duration,
    use_color: bool,
) {
    use std::fmt::Write;
    let mut md = String::new();

    writeln!(md, "# Shatter Run Report").unwrap();
    writeln!(md).unwrap();
    writeln!(md, "**Repository**: {}", root.display()).unwrap();
    writeln!(md, "**Elapsed**: {:.1}s", elapsed.as_secs_f64()).unwrap();
    writeln!(md).unwrap();

    // Files discovered
    let total_files = ts_files.len() + go_files.len() + rs_files.len();
    writeln!(md, "## Files Discovered").unwrap();
    writeln!(md).unwrap();
    writeln!(md, "| Language | Files |").unwrap();
    writeln!(md, "|----------|-------|").unwrap();
    if !ts_files.is_empty() {
        writeln!(md, "| TypeScript | {} |", ts_files.len()).unwrap();
    }
    if !go_files.is_empty() {
        writeln!(md, "| Go | {} |", go_files.len()).unwrap();
    }
    if !rs_files.is_empty() {
        writeln!(md, "| Rust | {} |", rs_files.len()).unwrap();
    }
    writeln!(md, "| **Total** | **{total_files}** |").unwrap();
    writeln!(md).unwrap();

    // Functions analyzed
    let total_branches: usize = registry.entries().iter().map(|e| e.branch_count).sum();
    writeln!(md, "## Functions Analyzed").unwrap();
    writeln!(md).unwrap();
    writeln!(md, "- **Total functions**: {}", registry.len()).unwrap();
    writeln!(md, "- **Total branches**: {total_branches}").unwrap();
    writeln!(md, "- **Exported functions**: {}", registry.exported_functions().len()).unwrap();
    writeln!(md).unwrap();

    // Call graph summary
    writeln!(md, "## Call Graph").unwrap();
    writeln!(md).unwrap();
    writeln!(md, "- **Nodes**: {}", call_graph.node_count()).unwrap();
    writeln!(md, "- **Edges**: {}", call_graph.edge_count()).unwrap();
    writeln!(md, "- **Topological layers**: {}", layers.len()).unwrap();
    writeln!(md, "- **Cycles**: {}", cycles.len()).unwrap();
    if !cycles.is_empty() {
        writeln!(md).unwrap();
        for (i, cycle) in cycles.iter().enumerate() {
            writeln!(md, "  Cycle {}: {}", i + 1, cycle.join(" <-> ")).unwrap();
        }
    }
    writeln!(md).unwrap();

    // Exploration results
    if !exploration_results.is_empty() {
        writeln!(md, "## Exploration Results").unwrap();
        writeln!(md).unwrap();
        writeln!(md, "| Function | Paths | Lines Covered | Coverage |").unwrap();
        writeln!(md, "|----------|-------|---------------|----------|").unwrap();

        let mut total_paths = 0;
        let mut total_covered = 0;
        let mut total_lines = 0u32;

        for (qname, result) in exploration_results {
            let pct = if result.total_lines > 0 {
                (result.lines_covered as f64 / result.total_lines as f64 * 100.0).min(100.0)
            } else {
                0.0
            };
            writeln!(
                md,
                "| {qname} | {} | {}/{} | {pct:.0}% |",
                result.unique_paths, result.lines_covered, result.total_lines
            ).unwrap();
            total_paths += result.unique_paths;
            total_covered += result.lines_covered;
            total_lines += result.total_lines;
        }

        let total_pct = if total_lines > 0 {
            (total_covered as f64 / total_lines as f64 * 100.0).min(100.0)
        } else {
            0.0
        };
        writeln!(
            md,
            "| **Total** | **{total_paths}** | **{total_covered}/{total_lines}** | **{total_pct:.0}%** |",
        ).unwrap();
        writeln!(md).unwrap();
    }

    print_markdown(&md, use_color);
}

/// Write analysis-only report to output directory.
fn write_analysis_report(
    dir: &Path,
    registry: &FunctionRegistry,
    call_graph: &CallGraph,
    root: &Path,
) -> Result<(), Box<dyn std::error::Error>> {
    std::fs::create_dir_all(dir)
        .map_err(|e| format!("failed to create output dir '{}': {e}", dir.display()))?;

    let summary_path = dir.join("analysis-summary.md");
    let mut content = String::new();
    content.push_str("# Analysis Summary\n\n");
    content.push_str(&format!("- Functions: {}\n", registry.len()));
    content.push_str(&format!("- Call graph edges: {}\n", call_graph.edge_count()));
    content.push_str(&format!("- Cycles: {}\n", call_graph.cycle_groups().len()));
    content.push_str("\n## Functions\n\n");

    for entry in registry.entries() {
        content.push_str(&format!(
            "- **{}** ({}): {} branches, {} deps\n",
            entry.name,
            relativize_path(&entry.file_path, root),
            entry.branch_count,
            entry.dependencies.len(),
        ));
    }

    std::fs::write(&summary_path, &content)
        .map_err(|e| format!("failed to write summary: {e}"))?;
    log::info!("Wrote analysis report to {}", summary_path.display());

    Ok(())
}

/// Write full run report with per-function files to output directory.
fn write_run_report(
    dir: &Path,
    call_graph: &CallGraph,
    exploration_results: &[(String, explorer::ObservationOutput)],
) -> Result<(), Box<dyn std::error::Error>> {
    std::fs::create_dir_all(dir)
        .map_err(|e| format!("failed to create output dir '{}': {e}", dir.display()))?;

    for (qname, result) in exploration_results {
        let safe_name = qname.replace("::", "__").replace('/', "_");
        let func_path = dir.join(format!("{safe_name}.md"));

        let pct = if result.total_lines > 0 {
            (result.lines_covered as f64 / result.total_lines as f64 * 100.0).min(100.0)
        } else {
            0.0
        };

        let mut content = String::new();
        content.push_str(&format!("# {qname}\n\n"));
        content.push_str(&format!("- **Iterations**: {}\n", result.iterations));
        content.push_str(&format!("- **Unique paths**: {}\n", result.unique_paths));
        content.push_str(&format!(
            "- **Line coverage**: {}/{} ({pct:.0}%)\n",
            result.lines_covered, result.total_lines
        ));

        if !result.new_path_executions.is_empty() {
            content.push_str("\n## Discovered Paths\n\n");
            for (i, exec) in result.new_path_executions.iter().enumerate() {
                let inputs_str: Vec<String> = exec.inputs.iter().map(|v| v.to_string()).collect();
                let outcome = if let Some(ref err) = exec.thrown_error {
                    format!("THROWS {err}")
                } else {
                    match &exec.return_value {
                        Some(v) if !v.is_null() => format!("returns {v}"),
                        _ => "returns void".to_string(),
                    }
                };
                content.push_str(&format!(
                    "{}. Input: ({}) -> {}\n",
                    i + 1,
                    inputs_str.join(", "),
                    outcome
                ));
            }
        }

        // Add call graph info
        let callees = call_graph.callees_of(qname);
        let callers = call_graph.callers_of(qname);
        if !callees.is_empty() || !callers.is_empty() {
            content.push_str("\n## Call Graph\n\n");
            if !callees.is_empty() {
                content.push_str(&format!("- **Calls**: {}\n", callees.join(", ")));
            }
            if !callers.is_empty() {
                content.push_str(&format!("- **Called by**: {}\n", callers.join(", ")));
            }
        }

        std::fs::write(&func_path, &content)
            .map_err(|e| format!("failed to write {}: {e}", func_path.display()))?;
    }

    log::info!(
        "Wrote {} per-function report(s) to {}",
        exploration_results.len(),
        dir.display()
    );

    Ok(())
}

/// Shutdown all frontends in a map.
async fn shutdown_all_frontends(frontends: HashMap<DiscoveryLanguage, Frontend>) {
    for (_, frontend) in frontends {
        if let Err(e) = frontend.shutdown().await {
            log::warn!("frontend shutdown error: {e}");
        }
    }
}

async fn shutdown_frontend(frontend: Frontend) {
    if let Err(e) = frontend.shutdown().await {
        log::warn!("frontend shutdown error: {e}");
    }
}

/// Run the stale command: check which functions are stale relative to a spec file.
///
/// Returns `Ok(true)` if all functions are fresh, `Ok(false)` if any are stale or removed.
// Each argument corresponds to a CLI flag; this is only called from one callsite.
#[allow(clippy::too_many_arguments)]
async fn run_stale(
    source: &str,
    spec_path: &Path,
    format: &str,
    request_timeout: u64,
    exec_timeout: u64,
    build_timeout: u64,
    memory_limit: Option<u64>,
    log_level: LogLevel,
    project_dir: Option<&Path>,
) -> Result<bool, Box<dyn std::error::Error>> {
    let target = parse_target(source)?;
    let file_str = target.file.to_string_lossy();
    let project_root_str = resolve_project_root(project_dir, &target.file);

    let req_timeout = Duration::from_secs(request_timeout);
    let config = frontend_config(target.language, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;
    let mut frontend = Frontend::spawn(&config).await.map_err(|e| {
        format!("failed to spawn {} frontend: {e}", target.language.label())
    })?;

    let analyze_response = frontend
        .send(ProtoCommand::Analyze {
            file: file_str.to_string(),
            function: target.function.clone(),
            project_root: project_root_str,
        })
        .await
        .map_err(|e| format!("analyze failed: {e}"))?;

    let functions = match &analyze_response.result {
        ResponseResult::Analyze { functions } => functions.clone(),
        ResponseResult::Error { code, message, .. } => {
            shutdown_frontend(frontend).await;
            return Err(format!("analyze error ({code:?}): {message}").into());
        }
        other => {
            shutdown_frontend(frontend).await;
            return Err(format!("unexpected analyze response: {other:?}").into());
        }
    };

    shutdown_frontend(frontend).await;

    let existing = shatter_core::spec::read_file_spec_bundle(spec_path)
        .map_err(|e| format!("failed to read spec file {}: {e}", spec_path.display()))?;

    let plan = shatter_core::spec::compute_incremental_plan(&target.file, &functions, &existing)
        .map_err(|e| format!("failed to compute incremental plan: {e}"))?;

    let all_fresh = plan.stale.is_empty() && plan.removed.is_empty();

    if format == "json" {
        let output = serde_json::json!({
            "stale": plan.stale,
            "fresh": plan.fresh,
            "removed": plan.removed,
            "all_fresh": all_fresh,
        });
        println!("{}", serde_json::to_string_pretty(&output)?);
    } else {
        if !plan.stale.is_empty() {
            println!("Stale ({}):", plan.stale.len());
            for name in &plan.stale {
                println!("  {name}");
            }
        }
        if !plan.fresh.is_empty() {
            println!("Fresh ({}):", plan.fresh.len());
            for name in &plan.fresh {
                println!("  {name}");
            }
        }
        if !plan.removed.is_empty() {
            println!("Removed ({}):", plan.removed.len());
            for name in &plan.removed {
                println!("  {name}");
            }
        }
        if all_fresh {
            println!("All functions are fresh.");
        }
    }

    Ok(all_fresh)
}

