                language.as_deref(),
                &include,
                &exclude,
                changed,
                since.as_deref(),
                include_untracked,
                all,
                max_depth,
                max_iterations,
                timeout_total,
                cache_dir.as_deref(),
                no_cache,
                request_timeout,
                exec_timeout,
                build_timeout,
                parallelism,
                timeout_per_fn,
                timeout_explore,
                output.as_deref(),
                &format,
                progress,
