                build_timeout,
                log_level,
                memory_limit,
                cli.project_dir.as_deref(),
            )
            .await
        }
        CliCommand::Run {
            path,
            output_dir,
            max_iterations,
            timeout,
            analyze_only,
            request_timeout,
            exec_timeout,
            build_timeout,
            solver_timeout: _,
            memory_limit,
        } => {
            run_run(
                &path,
                output_dir.as_deref(),
